window.__QUIZ_DATA__=[{"id":"objective>Mathematics>2022>1","subject":"Mathematics","year":"2022","type":"Objective","topic":"NUMBER AND NUMERATION : FRACTIONS, DECIMALS AND APPROXIMATIONS","question":"Evaluate, correct to four significant figures, (573.06 \u00d7 184.25).","images":[],"options":{"A":"105600.00","B":"105622.00","C":"105500.00","D":"105532.00"},"answer":"A","explanation":"573.06 \u00d7 184.25 = 105586.305  105600.00 to 4 significant figures","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2022>2","subject":"Mathematics","year":"2022","type":"Objective","topic":"NUMBER AND NUMERATION : NUMBER BASES","question":"Change 432five to a number in base three.","images":[],"options":{"A":"10100three","B":"11100three","C":"11101three","D":"10110three"},"answer":"B","explanation":"432five to base ten  4\u00d752 + 3\u00d75 + 2\u00d750 = 100 + 15 + 2 = 117  117 to base three  3 1173 39 03 13 03 4 13 1 1  0 1  writing from bottom to top  11100three","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2022>3","subject":"Mathematics","year":"2022","type":"Objective","topic":"NUMBER AND NUMERATION : SETS","question":"Given that A and B are sets such that n(A) = 8, n(B) = 12 and  n(A\u2229B) = 3, find n(A\u222aB).","images":[],"options":{"A":"15","B":"17","C":"20","D":"23"},"answer":"B","explanation":"n(A\u222aB) = (n(A) - n(A\u2229B)) + (n(B) - n(A\u2229B)) + n(A\u2229B)  n(A\u222aB) = (8-3) + (12-3) + 3  n(A\u222aB) = 5 + 9 + 3  n(A\u222aB) = 17","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2022>4","subject":"Mathematics","year":"2022","type":"Objective","topic":"NUMBER AND NUMERATION : SURDS -RADICALS","question":"If \u221a24 + \u221a96 - \u221a600 = y\u221a6 , find the value of y","images":[],"options":{"A":"4","B":"2","C":"-2","D":"-4"},"answer":"D","explanation":"\u221a(6\u00d74) + \u221a(6\u00d716) - \u221a(6\u00d7100)  \u221a(6\u00d722) + \u221a(6\u00d742) - \u221a(6\u00d7102)  \u221a6\u00d7\u221a22 + \u221a6\u00d7\u221a42 - \u221a6\u00d7\u221a102  2\u221a6 + 4\u221a6 - 10\u221a6  (2+4-10)\u221a6  -4\u221a6","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>2022>5","subject":"Mathematics","year":"2022","type":"Objective","topic":"NUMBER AND NUMERATION : MODULAR ARITHMETIC","question":"Evaluate 23 \u00d7 54 (mod7).","images":[],"options":{"A":"2","B":"3","C":"5","D":"6"},"answer":"B","explanation":"23\u00d754 = 1242  1242/7 = 177 remainder 3  1242(mod7) = 3","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2022>6","subject":"Mathematics","year":"2022","type":"Objective","topic":"NUMBER AND NUMERATION : LAWS OF INDICES","question":"If 43x = 16x+1, find the value of x","images":[],"options":{"A":"-2","B":"2","C":"1","D":"-1"},"answer":"B","explanation":"43x = 16x+1  22(3x) = 24(x+1)  since they have the same base, we can equate the power  2(3x) = 4(x+1)  6x = 4x+4  6x - 4x = 4  2x = 4  x = 2","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2022>7","subject":"Mathematics","year":"2022","type":"Objective","topic":"NUMBER AND NUMERATION : PROFIT AND LOSS","question":"A weaver bought a bundle of grass for $50.00 from which he made 8 mats. If each mat was sold for $15.00, find the percentage profit.","images":[],"options":{"A":"240%","B":"140%","C":"120%","D":"40%"},"answer":"B","explanation":"C.P = $50.00, S.P = 8 \u00d7 $15.00 = $120.00  profit(P) = S.P - C.P  P = 120 - 50 = $70  %P=PC.P\u00d7100%  %P=7050\u00d7100%  %P = 1.4 \u00d7 100%  %P = 140%","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2022>8","subject":"Mathematics","year":"2022","type":"Objective","topic":"NUMBER AND NUMERATION : SEQUENCE AND SERIES","question":"Find the 17th term of the Arithmetic Progression (A.P): -6, -1, 4, ...","images":[],"options":{"A":"-19","B":"-86","C":"74","D":"79"},"answer":"C","explanation":"U4 = a + (n-1)d, a = first term = -6, n = nth term = 17, d = difference= -1 - (-6) = 5  U4 = -6 + (17-1)5  U4 = -6 + 16\u00d75  U4 = -6 + 80  U4 = 74","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>2022>9","subject":"Mathematics","year":"2022","type":"Objective","topic":"NUMBER AND NUMERATION : VARIATION","question":"M varies directly as n and inversely as the square of p. If M = 3 when n = 2 and p = 1, find M in terms of n and p.","images":[],"options":{"A":"M=3n2p2","B":"M=2n3p2","C":"M=2n3p","D":"M=3n22p2"},"answer":"A","explanation":"M \u221d n and M \u221d1/p2  M \u221dn/p2  M=knp2  where k is the constant  k=Mp2n  when M = 3, n = 2 and p = 1  k=3\u00d7122  k = 3/2   FromM=knp2  M=3n2p2","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2022>10","subject":"Mathematics","year":"2022","type":"Objective","topic":"ALGEBRAIC PROCESSES : ALGEBRAIC FRACTIONS","question":"If a = 3 and b = -7, find the value of   5b+(a+b)2(a-b)2","images":[],"options":{"A":"0.51","B":"0.19","C":"-0.19","D":"-0.51"},"answer":"C","explanation":"5b+(a+b)2(a-b)2  5(-7)+(3-7)2(3+7)2  -35+(-4)2(10)2  -35+16100  -19100  -0.19","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2022>11","subject":"Mathematics","year":"2022","type":"Objective","topic":"NUMBER AND NUMERATION : RATIO, PROPORTIONS AND RATES","question":"Three boys shared D10,500.00 in the ratio 6:7:8. Find the largest share.","images":[],"options":{"A":"D4,000.00","B":"D5,000.00","C":"D4,500.00","D":"D3,500.00"},"answer":"A","explanation":"The largest share is the ratio 8, total ratio = 6+7+8 = 21  Thelargestshareis821\u00d7D10,500  8\u00d71050021  D4,000.00","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2022>12","subject":"Mathematics","year":"2022","type":"Objective","topic":"NUMBER AND NUMERATION : PERCENTAGE ERROR","question":"The length of a piece of stick is 1.75m. A boy measured it as 1.80m. Find the percentage error.","images":[],"options":{"A":"44/7%","B":"26/7%","C":"27/9%","D":"47/9%"},"answer":"B","explanation":"measured error = 1.80m - 1.75m = 0.05m  the actual length = 1.75m  %error=error(actual-length)\u00d7100%  %error=0.051.75\u00d7100%  %error=135\u00d7100%  %error=100%35  %error=20%7  %error = 26/7%","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2022>13","subject":"Mathematics","year":"2022","type":"Objective","topic":"ALGEBRAIC PROCESSES : SIMULTANEOUS LINEAR EQUATIONS IN TWO VARIABLES","question":"If 5x + 3y = 4 and 5x - 3y = 2, what is the value of (25x2 - 9y2)?","images":[],"options":{"A":"20","B":"16","C":"2","D":"8"},"answer":"D","explanation":"5x + 3y = 4 .........equation1  5x - 3y = 2 ..........equation2  subtract equation2 from equation1  6y = 2  y=13  sub for y in equation1  5x+3(13)=4  5x + 1 = 4  5x = 3  x=35  25x2-9y2=25(35)2-9(13)2  25(925)-9(19)  9 - 1 = 8","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2022>14","subject":"Mathematics","year":"2022","type":"Objective","topic":"ALGEBRAIC PROCESSES : FORMULATION AND EVALUATION OF ALGEBRAIC PROCESSES","question":"Mary has $3.00 more than Ben but $5.00 less than Jane. If Mary has $x, how much does Jane and Ben have altogether?","images":[],"options":{"A":"$(2x-8)","B":"$(2x+8)","C":"$(2x-2)","D":"$(2x+2)"},"answer":"D","explanation":"Mary has $x  Ben has $(x-3)  Jane has $(x+5)  Jane and Ben has $(x-3) + $(x+5) = $(2x+2)","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2022>15","subject":"Mathematics","year":"2022","type":"Objective","topic":"NUMBER AND NUMERATION : LOGICAL REASONING","question":"Consider the statements:    p: Stephen is intelligent  q: Stephen is good at Mathematics    If p \u21e8 q, which of the following is a valid conclusion?","images":[],"options":{"A":"If Stephen is good at Mathematics, then he is intelligent","B":"If Stephen is not good at Mathematics, then he is not intelligent","C":"If Stephen is not intelligent, then he is not good at Mathematics","D":"If Stephen is not good at Mathematics, then he is intelligent"},"answer":"B","explanation":"\"If Stephen is good at Mathematics, then he is intelligent\" can be written as q \u21e8 p    \"If Stephen is not good at Mathematics, then he is not intelligent\" can be written as ~q \u21e8 ~p    \"If Stephen is not intelligent, then he is not good at Mathematics\" can be written as ~p \u21e8 ~q    \"If Stephen is not good at Mathematics, then he is intelligent\" can be written as ~q \u21e8 p    Below is the truth table for implication (\u21e8)    pq~p~qp \u21e8 qq \u21e8 p~p \u21e8 ~q~p \u21e8 qp \u21e8 ~q~q \u21e8 ~pFFTTTTTFTTFTTFTFFTTTTFFTFTTTTFTTFFTTTTFT    From the truth table, it is only the output of ~q \u21e8 ~p that is equal to the output of p \u21e8 q.    Therefore, \"If Stephen is not good at Mathematics, then he is not intelligent\" is the correct answer.","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2022>16","subject":"Mathematics","year":"2022","type":"Objective","topic":"ALGEBRAIC PROCESSES : ALGEBRAIC FRACTIONS","question":"What value of p will make (x2 - 4x + p) a perfect square?","images":[],"options":{"A":"-2","B":"16","C":"4","D":"-8"},"answer":"C","explanation":"x2 - bx + c = (x + b/2)2  c = (b/2)2  x2 - 4x + p   p = (-4/2)2  p = -22  p = 4","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>2022>17","subject":"Mathematics","year":"2022","type":"Objective","topic":"ALGEBRAIC PROCESSES : LINEAR EQUATIONS IN ONE VARIABLE","question":"Findthevalueofxsuchthat1x+43x-56x+1iszero.","images":[],"options":{"A":"16","B":"14","C":"-32","D":"-76"},"answer":"C","explanation":"1x+43x-56x+1=0  6+8-5+6x6x=0  9+6x6x=0  9 + 6x = 6x(0)  9 + 6x = 0  6x = -9  x=-96  x=-32","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2022>18","subject":"Mathematics","year":"2022","type":"Objective","topic":"ALGEBRAIC PROCESSES : CHANGE OF SUBJECT OF A FORMULA/RELATION","question":"Maketthesubjectofk=m\u221a(t - p)r","images":[],"options":{"A":"t=rk2+pm2","B":"t=rk2+pm2m2","C":"t=rk2-pm2","D":"t=rk2+p2m2"},"answer":"B","explanation":"k=m\u221at-pr  divide by both sides by m  km=\u221at-pr  square both sides  (km)2=t-pr  multiply both sides by r  rk2m2=t-p  add p to both sides  t=rk2m2+p  t=rk2+pm2m2","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>2022>19","subject":"Mathematics","year":"2022","type":"Objective","topic":"PLANE GEOMETRY : ANGLES","question":"In the digram, |XY| = |YZ| and \u2220XYZ = 130\u2218. Find the value of y.","images":["data:image/png;base64,"],"options":{"A":"50\u2218","B":"65\u2218","C":"25\u2218","D":"155\u2218"},"answer":"D","explanation":"\u2220YZX = \u2220YXZ (two opposite angles of an isosceles triangle are equal)  \u2220YZX + \u2220YXZ + 130\u2218 = 180\u2218 (sum of angles in a triangle)  \u2220YZX + \u2220YXZ = 180\u2218 - 130\u2218  2\u2220YZX = 50\u2218   \u2220YZX=50\u22182  \u2220YZX = 25\u2218  y + \u2220YZX = 180\u2218 (angle on a straight line)  y + 25\u2218 = 180\u2218  y = 180\u2218 - 25\u2218  y = 155\u2218","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2022>20","subject":"Mathematics","year":"2022","type":"Objective","topic":"PLANE GEOMETRY : ANGLES AND INTERCEPTS ON PARALLEL LINES","question":"An exterior angle of a regular polygon is 22.5\u2218. Find the number of sides.","images":[],"options":{"A":"13","B":"14","C":"15","D":"16"},"answer":"D","explanation":"The sum of exterior angles of a polygon is 360\u2218.  360\u221822.5\u2218  16","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>2022>21","subject":"Mathematics","year":"2022","type":"Objective","topic":"PLANE GEOMETRY : CIRCLES","question":"In the diagram, \u2220POQ = 150\u2218 and the radius of the circle PSQR is 4.2cm.  [Take \u03c0 = 22/7]    Find the length of the minor arc PRQ.","images":["data:image/png;base64,"],"options":{"A":"11.00cm","B":"15.40cm","C":"17.64cm","D":"23.10cm"},"answer":"A","explanation":"Lengthofanarc=\u03b8360\u00d72\u03c0r  \u03b8 = 150\u2218, r = 4.2cm  Lengthofarc PRQ=150360\u00d72\u00d7227\u00d74.2  arcPRQ=512\u00d72\u00d722\u00d70.6  arc PRQ = 11cm","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2022>22","subject":"Mathematics","year":"2022","type":"Objective","topic":"PLANE GEOMETRY : CIRCLES","question":"In the diagram, \u2220POQ = 150\u2218 and the radius of the circle PSQR is 4.2cm.  [Take \u03c0 = 22/7]Find the area of the sector OPSQ","images":["data:image/png;base64,"],"options":{"A":"15.40cm2","B":"17.64cm2","C":"23.10cm2","D":"32.34cm2"},"answer":"D","explanation":"Areaofasector=\u03b8360\u00d7\u03c0r2  \u03b8 = 360-150 = 210\u2218, r = 4.2cm  AreaofsectorOPSQ=210360\u00d7227\u00d74.22    AreaofsectorOPSQ=712\u00d7227\u00d74.22  Area of sector OPSQ = 32.34cm2","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2022>23","subject":"Mathematics","year":"2022","type":"Objective","topic":"TRIGONOMETRY : ANGLES OF ELEVATION AND DEPRESSION","question":"A ladder 6m long leans against a vertical wall at an angle 53\u2218 to the horizontal. How high up the wall does the ladder reach?","images":[],"options":{"A":"3.611m","B":"4.521m","C":"4.792m","D":"3.962m"},"answer":"C","explanation":"let h be the height of the wall  sin53\u2218=h6  h = 6sin53\u2218  h = 4.792m","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2022>24","subject":"Mathematics","year":"2022","type":"Objective","topic":"MENSURATION : AREAS","question":"A cylinder, opened at one end, has a radius of 3.5cm and height 8cm. Calculate the total surface area.  [Take \u03c0 = 22/7]","images":[],"options":{"A":"126.5cm2","B":"165.0cm2","C":"212.0cm2","D":"214.5cm2"},"answer":"D","explanation":"Total surface area of cylinder opened at one end = 2\u03c0rh + \u03c0r2  r = 3.5cm, h = 8cm  T.S.A = 2\u03c0rh + \u03c0r2  T.S.A=2\u00d7227\u00d73.5\u00d78+(227\u00d73.52)   T.S.A = 176 + 38.5  T.S.A = 214.5cm2","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2022>25","subject":"Mathematics","year":"2022","type":"Objective","topic":"PLANE GEOMETRY : ANGLES","question":"In the diagram, \u2220WZY and \u2220WYX are right angles. Find the perimeter of WXYZ.","images":["data:image/png;base64,"],"options":{"A":"30cm","B":"32cm","C":"35cm","D":"37cm"},"answer":"B","explanation":"WY is the hypothenus of triangle WYZ  |WY|2 = 42 + 32  |WY|2 = 16 + 9  |WY|2 = 25  |WY| = \u221a25  |WY| = 5cm  |WX|2 = 52 + 122  |WX|2 = 25 + 144  |WX|2 = 169  |WX| = \u221a169  |WX| = 13cm  Perimeter of WXYZ = |WX| + |XY| + |YZ| + |WZ|  Perimeter of WXYZ = 13 + 12 + 3 + 4  Perimeter of WXYZ = 32cm","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2022>26","subject":"Mathematics","year":"2022","type":"Objective","topic":"MENSURATION : AREAS","question":"The length of a rectangle is 10cm. If its perimeter is 28cm, find the area .","images":[],"options":{"A":"30cm2","B":"40cm2","C":"60cm2","D":"80cm2"},"answer":"B","explanation":"perimeter of rectangle (p) = 2(L + B)  L = length of the rectangle and B = breadth of the rectangle   L = 10cm  28 = 2(10 + B)  2B + 20 = 28  2B = 28-20  2B = 8  B =4  Area of rectangle = LB  A = 4 \u00d7 10  A = 40cm2","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2022>27","subject":"Mathematics","year":"2022","type":"Objective","topic":"PLANE GEOMETRY : ANGLES","question":"In the diagram, MRW and MNST are straight lines. |MN| = |NR|,  \u2220MNR = 110\u2218 and \u2220WRS = 86\u2218, Find the value of x.","images":["data:image/png;base64,"],"options":{"A":"86\u2218","B":"70\u2218","C":"51\u2218","D":"42\u2218"},"answer":"C","explanation":"Triangle RNM is an isosceles triangle, therefore \u2220MRN = \u2220RMN  2\u2220MRN + 110\u2218 = 180\u2218  2\u2220MRN = 180\u2218 - 110\u2218  2\u2220MRN = 70\u2218  \u2220MRN=70\u22182  \u2220MRN = 35\u2218  86\u2218 + \u2220SRN + \u2220MRN = 180\u2218  (sum of angle on a straight line)  \u2220SRN + 86\u2218 + 35\u2218 =180\u2218  \u2220SRN =180\u2218 - 86\u2218 - 35\u2218  \u2220SRN = 59\u2218  \u2220RNS + 110\u2218 = 180\u2218 (sum of angle on a straight line)  \u2220RNS = 180\u2218 - 110\u2218  \u2220RNS = 70\u2218  \u2220RNS + \u2220SRN + x = 180\u2218 (sum of angles in a triangle)  x + 70\u2218 + 59\u2218 = 180\u2218  x = 180\u2218 - 70\u2218 - 59\u2218  x = 51\u2218","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2022>28","subject":"Mathematics","year":"2022","type":"Objective","topic":"TRIGONOMETRY : ANGLES OF ELEVATION AND DEPRESSION","question":"A boy 1.4m tall, stood 10m away from a tree of height 12m. Calculate, correct to the nearest degree, the angle of elevation of the top of the tree from the boy's eyes.","images":[],"options":{"A":"71\u2218","B":"47\u2218","C":"19\u2218","D":"8\u2218"},"answer":"B","explanation":"the required height = height of the tree - the boy's height  12 - 1.4 = 10.6m  tanx=10.610  tanx = 1.06  x = tan-11.06  x = 47\u2218","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>2022>29","subject":"Mathematics","year":"2022","type":"Objective","topic":"TRIGONOMETRY : SINE, COSINE AND TANGENT OF AN ANGLE","question":"Given that sin(5x-28)\u2218 = cos(3x-50)\u2218, 0\u2218\u2264x\u226490\u2218, find the value of x.","images":[],"options":{"A":"39","B":"32","C":"21","D":"14"},"answer":"C","explanation":"sin\u03b8 = cos(90-\u03b8) (the sine of an angle = cosine of the complementary angle)  sin(5x-28)\u2218 = sin(90 - (3x-50))\u2218  sin(5x-28)\u2218 = sin(90 - 3x + 50)\u2218  sin(5x-28)\u2218 = sin(140 - 3x)\u2218  5x -28 = 140 -3x  5x + 3x = 140 + 28  8x = 168  x = 168/8  x = 21","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>2022>30","subject":"Mathematics","year":"2022","type":"Objective","topic":"ALGEBRAIC PROCESSES : DRAWING TANGENTS TO CURVES TO DETERMINE THE GRADIENT AT A GIVEN POINT","question":"In the diagram, MNR is a tangent to the circle centre O at N and \u2220NOS = 108\u2218.    Find \u2220OSN","images":["data:image/png;base64,"],"options":{"A":"72\u2218","B":"42\u2218","C":"36\u2218","D":"18\u2218"},"answer":"C","explanation":"\u2220OSN = \u2220ONS (base angles of an isosceles triangle)  2\u2220OSN + 108\u2218 = 180\u2218  2\u2220OSN = 180\u2218 - 108\u2218  2\u2220OSN = 72\u2218  \u2220OSN=72\u22182  \u2220OSN = 36\u2218","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2022>31","subject":"Mathematics","year":"2022","type":"Objective","topic":"PLANE GEOMETRY : CIRCLES","question":"In the diagram, MNR is a tangent to the circle centre O at N and \u2220NOS = 108\u2218.find \u2220SNR","images":["data:image/png;base64,"],"options":{"A":"36\u2218","B":"42\u2218","C":"54\u2218","D":"72\u2218"},"answer":"C","explanation":"\u2220ONR = 90\u2218 (the angle between a tangent and a radius is 90\u2218)  \u2220SNR + \u2220ONS = 90\u2218  \u2220SNR + 36\u2218 = 90\u2218  \u2220SNR = 90\u2218 - 36\u2218  \u2220SNR = 54\u2218","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2022>32","subject":"Mathematics","year":"2022","type":"Objective","topic":"STATISTICS AND PROBABILITY. : PROBABILITY","question":"Mrs Gabriel is pregnant. The probability that she will give birth to a girl is 1/2 and the probability that the baby will have blue eyes is 1/4. What is the probability that she will give birth to a girl with blue eyes?","images":[],"options":{"A":"1","B":"34","C":"18","D":"14"},"answer":"C","explanation":"it is a non mutual exclusive event  12\u00d714  18","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2022>33","subject":"Mathematics","year":"2022","type":"Objective","topic":"STATISTICS AND PROBABILITY. : STATISTICS","question":"The mean of a set of 10 numbers is 56. If the mean of the first nine numbers is 55, find the 10th number.","images":[],"options":{"A":"75","B":"65","C":"55","D":"45"},"answer":"B","explanation":"\u03bc=\u2211xN  \u03bc = 56, N =10  \u2211x = \u03bcN   \u2211x = 10(56)  \u2211x = 560  \u03bc for the first nine = 55  \u2211x9 = 9 \u00d7 55 = 495  x10 = \u2211x - \u2211x9  x10 = 560 - 495  x10 = 65","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2022>34","subject":"Mathematics","year":"2022","type":"Objective","topic":"ALGEBRAIC PROCESSES : FORMULATION AND EVALUATION OF ALGEBRAIC PROCESSES","question":"Simplify:2-18m21+3m","images":[],"options":{"A":"2(1 + 3m)","B":"2(1 + 3m2)","C":"2(1 - 3m)","D":"2(1 - 3m2)"},"answer":"C","explanation":"2-18m21+3m  2(1-9m2)1+3m  2((1-3m)(1+3m))1+3m(differenceof2squares)  2(1-3m)","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2022>35","subject":"Mathematics","year":"2022","type":"Objective","topic":"PLANE GEOMETRY : CIRCLES","question":"The diagram shows triangle PQR inscribed in a circle. PS is a tangent to the circle at P.  Find \u2220PRQ","images":["data:image/png;base64,"],"options":{"A":"49\u2218","B":"58\u2218","C":"73\u2218","D":"131\u2218"},"answer":"A","explanation":"\u2220PQR = \u2220SPR (the angle btween the tangent and a chord at the point of contact is equal to the angle in the alternate segment)  \u2220PQR = 73\u2218  \u2220PRQ +\u2220PQR + 58\u2218 = 180\u2218 (sum of angles in a triangle)  \u2220PRQ +73\u2218 + 58\u2218 = 180\u2218  \u2220PRQ = 180\u2218 - 73\u2218 - 58\u2218  \u2220PRQ = 180\u2218 - 131\u2218  \u2220PRQ = 49\u2218","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2022>36","subject":"Mathematics","year":"2022","type":"Objective","topic":"PLANE GEOMETRY : CIRCLES","question":"In the diagram, triangle MNR is inscribed in circle MNR and PQ is a straight line. if \u2220MRN = 41\u2218 and \u2220PMR 141\u2218, find \u2220QNR.","images":["data:image/png;base64,"],"options":{"A":"39\u2218","B":"80\u2218","C":"110\u2218","D":"141\u2218"},"answer":"B","explanation":"\u2220MNR + 41\u2218 =141\u2218  \u2220MNR = 141\u2218 - 41\u2218  \u2220MNR = 100\u2218  \u2220MNR + \u2220QNR = 180\u2218  \u2220QNR + 100\u2218= 180\u2218  \u2220QNR = 180\u2218 - 100\u2218  \u2220QNR = 80\u2218","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2022>37","subject":"Mathematics","year":"2022","type":"Objective","topic":"ALGEBRAIC PROCESSES : LINEAR INEQUALITIES","question":"Solvey+24-y-13>1.","images":[],"options":{"A":"y","B":"y","C":"y","D":"y"},"answer":"B","explanation":"y+24-y-13>1  multiply through by 12  3(y+2) - 4(y-1) > 12  3y + 6 - 4y + 4 > 12  -y + 10 > 12  -y > 12 -10  -y > 2  y","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2022>38","subject":"Mathematics","year":"2022","type":"Objective","topic":"STATISTICS AND PROBABILITY. : STATISTICS","question":"The ages (years) of some members in a singing group are: 12, 47, 49, 15, 43, 41, 13, 39, 43, 41 and 36.    Find the lower quartile","images":[],"options":{"A":"12","B":"13","C":"15","D":"20"},"answer":"C","explanation":"12,13,15,36,39,41,41,43,43,47,49  lowerquartile(Q1)=N+14  N = 11  Q1=11+14  Q1=124  Q1 = 3  the lower quartile is the third member 15","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2022>39","subject":"Mathematics","year":"2022","type":"Objective","topic":"STATISTICS AND PROBABILITY. : STATISTICS","question":"The ages (years) of some members in a singing group are: 12, 47, 49, 15, 43, 41, 13, 39, 43, 41 and 36.Find the mean.","images":[],"options":{"A":"33.35","B":"35.54","C":"34.45","D":"36.44"},"answer":"C","explanation":"\u03bc=\u2211xN  \u03bc=12+13+15+36+39+41+41+43+43+47+4911  \u03bc=37911  \u03bc = 34.45","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2022>40","subject":"Mathematics","year":"2022","type":"Objective","topic":"MENSURATION : VOLUMES","question":"Find the correct to two decimal places, the volume of a sphere whose radius is 3cm.  [Take \u03c0 = 22/7]","images":[],"options":{"A":"72.57cm3","B":"88.12cm3","C":"105.29cm3","D":"113.14cm3"},"answer":"D","explanation":"Volume of a sphere(V) = 4/3 \u03c0r3  r = 3cm  V=43\u00d7227\u00d733  V=43\u00d7227\u00d727  V = 113.14cm3","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2022>41","subject":"Mathematics","year":"2022","type":"Objective","topic":"MENSURATION : AREAS","question":"The lengths of the parallel sides of a trapezium are 9cm and 12cm. If the area of the trapezium is 105cm2, find the perpendicular distance between the parallel sides.","images":[],"options":{"A":"5cm","B":"7cm","C":"10cm","D":"15cm"},"answer":"C","explanation":"Area of trapezium (A) = 1/2(a+b)h  a = 9cm, b=12cm, h = ?, A = 105cm2  h=2A(a+b)  h=2(105)(9+12)  h=21021  h = 10cm","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2022>42","subject":"Mathematics","year":"2022","type":"Objective","topic":"MENSURATION : VOLUMES","question":"Find the volume of a cone of radius 3.5cm and vertical height 12cm.  [Take \u03c0 = 22/7]","images":[],"options":{"A":"15.5cm3","B":"21.0cm3","C":"142.0cm3","D":"154.0cm3"},"answer":"D","explanation":"Volume of a cone(V) = 1/3\u03c0r2h  r = 3.5cm, h = 12cm  V=13\u00d7227\u00d73.52\u00d712  V = 154cm3","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2022>43","subject":"Mathematics","year":"2022","type":"Objective","topic":"STATISTICS AND PROBABILITY. : PROBABILITY","question":"A local community has two newspapers: the Morning Times and the Evening Dispatch. The Morning Times is read by 45% of households and the Evening Dispatch by 60%. If 20% of the households read both papers, find the probability that a particular household reads at least one paper.","images":[],"options":{"A":"0.45","B":"0.65","C":"0.85","D":"0.95"},"answer":"C","explanation":"(60-20)% read only Evening and (45-20)% read on Morning Times  (60-20)% + (45-20)% + 20% = 85%  \u223485% of the households read at least one of the papers  85100  0.85","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2022>44","subject":"Mathematics","year":"2022","type":"Objective","topic":"MENSURATION : AREAS","question":"A rectangle has width 3/4cm and an area 33/8cm2. Find the length.","images":[],"options":{"A":"6cm","B":"41/2cm","C":"25/8cm","D":"12cm"},"answer":"B","explanation":"A = length \u00d7 width  33/8 = l \u00d7 3/4  l=278\u00d743  l=92  l = 41/2cm","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2022>45","subject":"Mathematics","year":"2022","type":"Objective","topic":"STATISTICS AND PROBABILITY. : STATISTICS","question":"The mean of two numbers x and y is 4. Find the mean of the four numbers x, 2x, y and 2y.","images":[],"options":{"A":"2","B":"4","C":"6","D":"8"},"answer":"C","explanation":"x+y2=4  x+y = 8  x = 8 - y ------equation1  x+2x+y+2y4  3x+3y4  from equation1 x = 8-y  3(8-y)+3y4  24-3y+3y4  24+04  244  6","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2022>46","subject":"Mathematics","year":"2022","type":"Objective","topic":"COORDINATE GEOMETRY OF STRAIGHT LINES : CONCEPT OF THE X-Y PLANE AND COORDINATES OF POINTS ON THE X-Y PLANE","question":"The straight line y = mx - 4 passes through the point (-4, 16). Calculate the gradient of the line.","images":[],"options":{"A":"-5","B":"-3","C":"3","D":"5"},"answer":"A","explanation":"y = mx - 4  x = -4, y = 16 and m = gradient  16 = m(-4) - 4  -4m = 16 + 4  -4m = 20  m=20-4  m = -5","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2022>47","subject":"Mathematics","year":"2022","type":"Objective","topic":"ALGEBRAIC PROCESSES : QUADRATIC EQUATIONS","question":"If the equation x2 - 5x + 6 = 0 and x2 + px + 6 = 0 have common roots, find the value of p.","images":[],"options":{"A":"5","B":"6","C":"-6","D":"-5"},"answer":"D","explanation":"comparing both equation  x2 - 5x + 6 =  x2 + px + 6   p = -5","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2022>48","subject":"Mathematics","year":"2022","type":"Objective","topic":"NUMBER AND NUMERATION : PROFIT AND LOSS","question":"A trader made a loss of 15% when an article was sold. Find the ratio of the selling price to the cost price.","images":[],"options":{"A":"3:20","B":"3:17","C":"17:20","D":"20:23"},"answer":"C","explanation":"cost price  = 100%  selling price = cost price - loss  selling price = (100 - 15)%  selling price = 85%  S.P : C.P  85:100  17:20","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2022>49","subject":"Mathematics","year":"2022","type":"Objective","topic":"NUMBER AND NUMERATION : LOGARITHMS","question":"Given that log327 = 2x + 1, find the value of x.","images":[],"options":{"A":"0","B":"1","C":"2","D":"3"},"answer":"B","explanation":"log327 = 2x + 1  log333 = 2x + 1  3log33 = 2x + 1  log33 = 1 (log to its own base = 1)  3 = 2x + 1  2x = 2  x =1","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2022>50","subject":"Mathematics","year":"2022","type":"Objective","topic":"ALGEBRAIC PROCESSES : QUADRATIC EQUATIONS","question":"Solve: 6x2 = 5x - 1","images":[],"options":{"A":"x = 2,3","B":"x = 0,3","C":"x = 1/2,1/3","D":"x = 1/2, -1/3"},"answer":"C","explanation":"6x2 =  5x - 1  6x2 - 5x + 1 = 0  6x2 -2x -3x +1 = 0  2x(3x - 1) - 1(3x -1) = 0  (2x-1)(3x-1) = 0  either 2x-1 = 0 or 3x-1 = 0  2x = 1 or 3x = 1  x=12orx=13","marks":"1","difficulty":"3"}];